const accounts = ['ACC-1001', 'ACC-1002', 'ACC-2001', 'ACC-2002', 'ACC-3001'];
const currencies = ['USD', 'EUR', 'GBP'];
const descriptions = ['Payment for services', 'Invoice INV-2024', 'Transfer to savings', 'Refund order #1234', 'Salary payment'];

const srcIdx = Math.floor(Math.random() * accounts.length);
let dstIdx = Math.floor(Math.random() * (accounts.length - 1));
if (dstIdx >= srcIdx) dstIdx++;

msg.payload = {
  eventId: 'evt-' + Date.now() + '-' + Math.random().toString(36).slice(2, 8),
  eventType: 'TRANSACTION_POSTED',
  timestamp: new Date().toISOString(),
  payload: {
    transactionId: 'txn-' + Date.now().toString(36) + Math.random().toString(36).slice(2, 6),
    sourceAccountId: accounts[srcIdx],
    destinationAccountId: accounts[dstIdx],
    amount: Math.round((Math.random() * 5000 + 10) * 100) / 100,
    currency: currencies[Math.floor(Math.random() * currencies.length)],
    description: descriptions[Math.floor(Math.random() * descriptions.length)]
  }
};

return msg;

const name = msg.topic || 'Test';
let code = msg.payload;
if (typeof code === 'object') {
  code = code.code !== undefined ? code.code : (code.exitCode !== undefined ? code.exitCode : JSON.stringify(code));
}
const status = Number(code) === 0 ? 'PASSED' : 'FAILED';
msg.payload = '=== ' + name + ' ===\nStatus: ' + status + '\nExit code: ' + code;
msg.status = { fill: Number(code) === 0 ? 'green' : 'red', shape: 'ring', text: status };
return msg;

